  ('rgn_samaria', '사마리아', '에브라임 산지 + 므낫세 일부. 세겜·실로·벧엘·도단·사마리아 성. 사사 에브라임부터 분열왕국 북이스라엘 수도, 신약 사마리아까지 통합.', '📍', null, 32.4, 35.25, '[[31.92, 35.02], [31.95, 35.1], [31.93, 35.2], [31.95, 35.32], [31.95, 35.45], [31.95, 35.52], [32.1, 35.55], [32.25, 35.55], [32.4, 35.55], [32.5, 35.5], [32.55, 35.4], [32.58, 35.25], [32.55, 35.12], [32.5, 35.0], [32.4, 34.95], [32.25, 34.95], [32.1, 34.95], [32.0, 34.95], [31.92, 34.97]]'::jsonb, 'region', null, null, 90, '{"era_patriarch","era_judges","era_monarchy","era_nt_public_ministry","era_nt_apostolic"}'::text[], '{}'::text[]),
